<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            user-select: none;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            overflow: hidden;
            height: 100vh;
            width: 100vw;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100%;
            height: calc(100% - 48px);
            background: linear-gradient(to bottom, #2e3440, #3b4252);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 48px;
            background-color: rgba(46, 52, 64, 0.9);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 1000;
            border-top: 1px solid #4c566a;
        }

        .launcher {
            width: 48px;
            height: 48px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: background-color 0.2s;
            border-radius: 4px;
            margin: 0 10px;
        }

        .launcher:hover {
            background-color: rgba(76, 86, 106, 0.5);
        }

        .launcher-icon {
            width: 32px;
            height: 32px;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 18px;
        }

        #open-files .launcher-icon {
            background-color: #007acc;
        }

        #open-notepad .launcher-icon {
            background-color: #d35400;
        }

        /* Windows */
        .window {
            position: absolute;
            width: 600px;
            height: 400px;
            min-width: 360px;
            min-height: 240px;
            background-color: #3d4555;
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            z-index: 100;
        }

        .window-header {
            height: 32px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 10px;
            cursor: default;
        }

        .window-title {
            color: white;
            font-size: 14px;
            font-weight: 500;
        }

        .window-controls {
            display: flex;
            gap: 8px;
        }

        .win-close {
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background-color: #bf616a;
            cursor: pointer;
            transition: transform 0.1s;
        }

        .win-close:hover {
            transform: scale(1.1);
        }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 15px;
            color: #d8dee9;
        }

        /* Files App */
        #files-window {
            top: 10%;
            left: 20%;
        }

        #files-path-container {
            display: flex;
            align-items: center;
            margin-bottom: 15px;
            background-color: rgba(0, 0, 0, 0.3);
            padding: 8px 12px;
            border-radius: 4px;
            font-family: monospace;
        }

        #files-path {
            color: #88c0d0;
            margin-left: 8px;
        }

        .fs-up-btn {
            background-color: #5e81ac;
            padding: 6px 12px;
            border-radius: 4px;
            cursor: pointer;
            display: flex;
            align-items: center;
            gap: 6px;
            font-size: 13px;
        }

        .fs-up-btn:hover {
            background-color: #81a1c4;
        }

        .fs-item {
            padding: 8px 12px;
            margin-bottom: 4px;
            border-radius: 4px;
            cursor: pointer;
            display: flex;
            align-items: center;
            gap: 8px;
            transition: background-color 0.2s;
        }

        .fs-item:hover {
            background-color: rgba(143, 188, 143, 0.2);
        }

        .fs-folder-icon {
            width: 20px;
            height: 20px;
            color: #d08770;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .fs-file-icon {
            width: 20px;
            height: 20px;
            color: #b48ead;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        /* Notepad App */
        #notepad-window {
            top: 15%;
            left: 30%;
        }

        .tabs-container {
            background-color: #4c566a;
            padding: 8px 0;
            display: flex;
            align-items: center;
            gap: 2px;
        }

        .tab {
            padding: 6px 16px;
            background-color: #3b4252;
            color: #d8dee9;
            border-radius: 6px 6px 0 0;
            cursor: pointer;
            font-size: 13px;
            transition: background-color 0.2s;
        }

        .tab.active {
            background-color: #4c566a;
            color: white;
        }

        .tab:hover:not(.active) {
            background-color: #434c5e;
        }

        .new-tab-btn {
            padding: 6px 12px;
            margin-left: auto;
            background-color: transparent;
            border: none;
            color: #d8dee9;
            cursor: pointer;
            font-size: 13px;
        }

        .new-tab-btn:hover {
            color: white;
        }

        #editor-container {
            flex: 1;
            display: flex;
            flex-direction: column;
            background-color: #2e3440;
        }

        #editor {
            flex: 1;
            width: 100%;
            height: 100%;
            background-color: #2e3440;
            color: #d8dee9;
            border: none;
            padding: 15px;
            font-family: monospace;
            font-size: 14px;
            resize: none;
            outline: none;
        }

        /* Dragging */
        .dragging {
            cursor: move;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div id="open-files" class="launcher">
                <div class="launcher-icon">📁</div>
            </div>
            <div id="open-notepad" class="launcher">
                <div class="launcher-icon">📝</div>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window" style="display: none;">
            <div class="window-header">
                <span class="window-title">Files</span>
                <div class="window-controls">
                    <div class="win-close"></div>
                </div>
            </div>
            <div class="window-content">
                <div id="files-path-container">
                    <button id="files-up" class="fs-up-btn">⬆️ Up</button>
                    <span id="files-path">/</span>
                </div>
                <div id="files-list"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window" style="display: none;">
            <div class="window-header">
                <span class="window-title">Notepad</span>
                <div class="window-controls">
                    <div class="win-close"></div>
                </div>
            </div>
            <div class="tabs-container" id="tabs">
                <!-- Tabs will be added here -->
            </div>
            <div id="editor-container">
                <textarea id="editor" placeholder="Type your notes here..."></textarea>
            </div>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            '/': ['bin', 'etc', 'home', 'usr', 'var'],
            '/bin': ['bash', 'ls', 'cp', 'mv', 'rm'],
            '/etc': ['config', 'hosts', 'passwd'],
            '/home': ['user'],
            '/home/user': ['Documents', 'Downloads', 'Pictures', 'notes.txt'],
            '/home/user/Documents': ['report.docx', 'resume.pdf'],
            '/home/user/Downloads': ['software.iso', 'update.tar.gz'],
            '/home/user/Pictures': ['wallpaper.png', 'screenshot.jpg'],
            '/usr': ['bin', 'lib', 'share'],
            '/var': ['log', 'cache', 'tmp']
        };

        // Files app state
        let currentPath = '/';
        const filesWindow = document.getElementById('files-window');
        const filesList = document.getElementById('files-list');
        const filesPathDisplay = document.getElementById('files-path');

        // Notepad app state
        let tabs = [];
        let activeTabId = null;
        let tabCounter = 0;

        // Initialize notepad from localStorage
        function initNotepad() {
            const savedTabs = localStorage.getItem('ubuntu_notepad_tabs');
            if (savedTabs) {
                try {
                    tabs = JSON.parse(savedTabs);
                    if (tabs.length > 0) {
                        activeTabId = tabs[0].id;
                        renderTabs();
                        loadActiveTabContent();
                    }
                } catch (e) {
                    createNewTab();
                }
            } else {
                createNewTab();
            }
        }

        // Save notepad state to localStorage
        function saveNotepad() {
            localStorage.setItem('ubuntu_notepad_tabs', JSON.stringify(tabs));
        }

        // Create new tab
        function createNewTab() {
            const id = `tab-${++tabCounter}`;
            tabs.push({
                id: id,
                title: `Tab ${tabs.length + 1}`,
                content: ''
            });
            activeTabId = id;
            renderTabs();
            saveNotepad();
        }

        // Render tab strip
        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';

            tabs.forEach(tab => {
                const tabElement = document.createElement('div');
                tabElement.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabElement.textContent = tab.title;
                tabElement.dataset.tabId = tab.id;

                // Click to switch tab
                tabElement.addEventListener('click', () => {
                    activeTabId = tab.id;
                    renderTabs();
                    loadActiveTabContent();
                });

                tabsContainer.appendChild(tabElement);
            });

            const newTabBtn = document.createElement('button');
            newTabBtn.id = 'new-tab';
            newTabBtn.className = 'new-tab-btn';
            newTabBtn.textContent = '+ New Tab';
            newTabBtn.addEventListener('click', createNewTab);
            tabsContainer.appendChild(newTabBtn);
        }

        // Load active tab content
        function loadActiveTabContent() {
            const editor = document.getElementById('editor');
            const activeTab = tabs.find(tab => tab.id === activeTabId);
            if (activeTab) {
                editor.value = activeTab.content;
                editor.focus();
            }
        }

        // Save current tab content
        function saveCurrentTabContent() {
            const editor = document.getElementById('editor');
            const activeTab = tabs.find(tab => tab.id === activeTabId);
            if (activeTab) {
                activeTab.content = editor.value;
                saveNotepad();
            }
        }

        // Files app functions
        function renderFilesList() {
            filesList.innerHTML = '';

            // Show up button for non-root directories
            if (currentPath !== '/') {
                const upBtn = document.createElement('div');
                upBtn.className = 'fs-item';
                upBtn.innerHTML = '<span class="fs-folder-icon">⬆️</span> Up';
                upBtn.addEventListener('click', navigateUp);
                filesList.appendChild(upBtn);
            }

            // Get items in current directory
            const items = fileSystem[currentPath] || [];

            // Separate folders and files, sort alphabetically
            const folders = items.filter(item => 
                item in fileSystem && !item.endsWith('.txt') && !item.endsWith('.docx') && !item.endsWith('.pdf')
            ).sort();

            const files = items.filter(item => 
                !item in fileSystem || item.endsWith('.txt') || item.endsWith('.docx') || item.endsWith('.pdf')
            ).sort();

            // Render folders
            folders.forEach(folder => {
                const folderPath = currentPath === '/' ? `/${folder}` : `${currentPath}/${folder}`;
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';
                itemDiv.innerHTML = '<span class="fs-folder-icon">📁</span>' + folder;
                itemDiv.addEventListener('dblclick', () => {
                    currentPath = folderPath;
                    updateFilesDisplay();
                });
                filesList.appendChild(itemDiv);
            });

            // Render files
            files.forEach(file => {
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';
                itemDiv.innerHTML = '<span class="fs-file-icon">📄</span>' + file;
                filesList.appendChild(itemDiv);
            });
        }

        function updateFilesDisplay() {
            // Update path display
            if (currentPath === '/') {
                filesPathDisplay.textContent = '/';
            } else {
                filesPathDisplay.textContent = currentPath;
            }

            renderFilesList();
        }

        function navigateUp() {
            if (currentPath !== '/') {
                const parts = currentPath.split('/');
                parts.pop();
                currentPath = parts.length === 1 ? '/' : parts.join('/');
                updateFilesDisplay();
            }
        }

        // Window dragging functionality
        let isDragging = false;
        let dragOffsetX = 0;
        let dragOffsetY = 0;
        let draggedWindow = null;

        function setupDrag(windowElement) {
            const header = windowElement.querySelector('.window-header');

            header.addEventListener('mousedown', (e) => {
                // Don't drag if clicking on close button
                if (e.target.classList.contains('win-close')) return;

                isDragging = true;
                draggedWindow = windowElement;

                const rect = windowElement.getBoundingClientRect();
                dragOffsetX = e.clientX - rect.left;
                dragOffsetY = e.clientY - rect.top;

                // Bring to front
                const allWindows = document.querySelectorAll('.window');
                let maxZIndex = 100;
                allWindows.forEach(win => {
                    if (parseInt(win.style.zIndex) > maxZIndex) {
                        maxZIndex = parseInt(win.style.zIndex);
                    }
                });
                windowElement.style.zIndex = maxZIndex + 1;
            });

            document.addEventListener('mousemove', (e) => {
                if (!isDragging || !draggedWindow) return;

                e.preventDefault();

                const desktop = document.getElementById('desktop');
                const desktopRect = desktop.getBoundingClientRect();

                let newX = e.clientX - desktopRect.left - dragOffsetX;
                let newY = e.clientY - desktopRect.top - dragOffsetY;

                // Keep window within desktop bounds
                const maxX = desktopRect.width - draggedWindow.offsetWidth;
                const maxY = desktopRect.height - draggedWindow.offsetHeight;

                if (newX < 0) newX = 0;
                if (newY < 0) newY = 0;
                if (newX > maxX) newX = maxX;
                if (newY > maxY) newY = maxY;

                draggedWindow.style.left = `${newX}px`;
                draggedWindow.style.top = `${newY}px`;
            });

            document.addEventListener('mouseup', () => {
                isDragging = false;
                draggedWindow = null;
            });
        }

        // Initialize everything
        document.addEventListener('DOMContentLoaded', () => {
            // Setup files app
            updateFilesDisplay();

            // Setup notepad app
            initNotepad();

            // Setup window drag functionality
            setupDrag(document.getElementById('files-window'));
            setupDrag(document.getElementById('notepad-window'));

            // Files up button
            document.getElementById('files-up').addEventListener('click', navigateUp);

            // Notepad tab switching and content saving
            const editor = document.getElementById('editor');
            editor.addEventListener('input', saveCurrentTabContent);

            // Launcher buttons
            document.getElementById('open-files').addEventListener('click', () => {
                filesWindow.style.display = 'flex';
                filesWindow.style.zIndex = 101;
            });

            document.getElementById('open-notepad').addEventListener('click', () => {
                notepadWindow.style.display = 'flex';
                notepadWindow.style.zIndex = 102;
            });

            // Close buttons
            const closeButtons = document.querySelectorAll('.win-close');
            closeButtons.forEach(btn => {
                btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const windowElement = btn.closest('.window');
                    if (windowElement) {
                        windowElement.style.display = 'none';
                    }
                });
            });

            // Click outside windows to focus them
            document.getElementById('desktop').addEventListener('click', () => {
                const allWindows = document.querySelectorAll('.window');
                let maxZIndex = 100;
                allWindows.forEach(win => {
                    if (parseInt(win.style.zIndex) > maxZIndex) {
                        maxZIndex = parseInt(win.style.zIndex);
                    }
                });

                // Reset z-indexes
                allWindows.forEach((win, index) => {
                    win.style.zIndex = 100 + index;
                });
            });

            const notepadWindow = document.getElementById('notepad-window');

            // New tab button
            document.getElementById('new-tab').addEventListener('click', createNewTab);
        });
    </script>
</body>
</html>
